import{_ as n,I as o,c as i,o as s,ai as r,j as a,J as d,a as t,w as c}from"./chunks/framework.DApawI3z.js";const T=JSON.parse('{"title":"自动安装","description":"使用exe安装程序自动完成安装","frontmatter":{"title":"自动安装","description":"使用exe安装程序自动完成安装","layout":"doc"},"headers":[],"relativePath":"docs/base/install.md","filePath":"docs/base/install.md"}'),g={name:"docs/base/install.md"},p={class:"tip custom-block"};function m(h,e,b,_,u,f){const l=o("font");return s(),i("div",null,[e[5]||(e[5]=r('<h1 id="prepare" tabindex="-1">准备工作 <a class="header-anchor" href="#prepare" aria-label="Permalink to “准备工作”">​</a></h1><h2 id="_1-下载并安装c-runtime" tabindex="-1">1. 下载并安装C++ runtime <a class="header-anchor" href="#_1-下载并安装c-runtime" aria-label="Permalink to “1. 下载并安装C++ runtime”">​</a></h2><h3 id="_1-1-下载c-runtime" tabindex="-1">1.1. 下载C++ runtime <a class="header-anchor" href="#_1-1-下载c-runtime" aria-label="Permalink to “1.1. 下载C++ runtime”">​</a></h3><p>访问<a href="https://aka.ms/vs/17/release/vc_redist.x64.exe" target="_blank" rel="noreferrer">微软官方地址</a>进行下载</p><h3 id="_1-2-安装c-runtime" tabindex="-1">1.2. 安装C++ runtime <a class="header-anchor" href="#_1-2-安装c-runtime" aria-label="Permalink to “1.2. 安装C++ runtime”">​</a></h3><p>双击下载下来的文件，先勾选<code>我同意许可条款和条件</code>，再点击<code>安装</code>。<br><img src="https://tc.ets2la.cn/d/img/25-12/20251202103155.png" alt="" loading="lazy"><br> 如果你双击打开C++ runtime的安装程序是这样的，这表明你已经有了基础的环境，直接点击 <code>关闭</code>即可。 <img src="https://tc.ets2la.cn/d/img/25-12/20251202094207.png" alt="" loading="lazy"></p><h1 id="安装软件" tabindex="-1">安装软件 <a class="header-anchor" href="#安装软件" aria-label="Permalink to “安装软件”">​</a></h1><h2 id="_2-下载安装程序并完成安装" tabindex="-1">2.下载安装程序并完成安装 <a class="header-anchor" href="#_2-下载安装程序并完成安装" aria-label="Permalink to “2.下载安装程序并完成安装”">​</a></h2><h3 id="_2-1-下载安装程序" tabindex="-1">2.1. 下载安装程序 <a class="header-anchor" href="#_2-1-下载安装程序" aria-label="Permalink to “2.1. 下载安装程序”">​</a></h3><p>前往软件在<a href="https://github.com" target="_blank" rel="noreferrer">GitHub</a>上的<a href="https://github.com/ETS2LA/installer/releases" target="_blank" rel="noreferrer">发布页</a>，下载最新地安装程序 <img src="https://tc.ets2la.cn/d/img/25-12/20251202105027.png" alt="" loading="lazy"></p>',10)),a("div",p,[e[1]||(e[1]=a("p",{class:"custom-block-title"},"提示",-1)),e[2]||(e[2]=a("p",null,[t("如果你无法通过GitHub下载到安装程序，我们同样提供"),a("a",{href:"https://www.ets2la.cn/installer",target:"_blank",rel:"noreferrer"},"镜像下载")],-1)),d(l,{color:"#ff0000"},{default:c(()=>[...e[0]||(e[0]=[t("PS",-1)])]),_:1}),e[3]||(e[3]=t(":使用镜像下载的文件会在文件名中携带更新日期信息，例如：",-1)),e[4]||(e[4]=a("code",null,"ETS2LA-Windows-Installer(update-10-10).exe",-1))]),e[6]||(e[6]=r('<h3 id="_2-2-运行安装程序" tabindex="-1">2.2. 运行安装程序 <a class="header-anchor" href="#_2-2-运行安装程序" aria-label="Permalink to “2.2. 运行安装程序”">​</a></h3><p>双击运行刚才下载的安装程序，可能会出现<code>Windows defender</code>的提示，直接点击<code>更多信息</code>，展开之后选择<code>仍要运行</code>即可。 <img src="https://tc.ets2la.cn/d/img/25-12/20250721084016.png" alt="" loading="lazy"><br> 在完成上一步之后会来到选择语言的界面，选择<code>Simplified Chinese</code>并点击OK即可。<br><img src="https://tc.ets2la.cn/d/img/25-12/20251202125608.png" alt="" loading="lazy"><br> 之后会进入到安装向导，点击<code>下一步</code>即可<br><img src="https://tc.ets2la.cn/d/img/25-12/20251202125735.png" alt="" loading="lazy"><br> 点击<code>我接受</code>以同意许可协议<br><img src="https://tc.ets2la.cn/d/img/25-12/20251202125809.png" alt="" loading="lazy"><br> 勾选<code>我已知晓，若曾为此安装程序付费，即表示我已受骗</code>并点击<code>下一步</code><br><img src="https://tc.ets2la.cn/d/img/25-12/20251202125900.png" alt="" loading="lazy"><br> 选择软件<code>安装目录</code>；建议使用<strong>盘符根目录</strong>以避免使用<strong>中文目录</strong>带来的无法安装的问题<br><img src="https://tc.ets2la.cn/d/img/25-12/20251202130133.png" alt="" loading="lazy"><br> 仓库地址选择<code>CNB</code>,Pypi Mirror选择<code>USTC</code>或<code>Aliyun</code>，然后点击下一步<br><img src="https://tc.ets2la.cn/d/img/25-12/20251202130358.png" alt="" loading="lazy"><br> 根据自己需要选择是否创建<code>开始菜单快捷方式和桌面快捷方式</code>，然后点击安装<br><img src="https://tc.ets2la.cn/d/img/25-12/20251202130552.png" alt="" loading="lazy"><br> 安装过程中点击<code>显示详情</code>可以查看安装进度，点击<code>显示详情</code>也是在安装出现问题时最直接能够看出问题出现在什么地方的方式 <img src="https://tc.ets2la.cn/d/img/25-12/20251202130738.png" alt="" loading="lazy"><br> 当出现这样的内容时，稍作等待，最终需要的时间取决于各位的硬盘速度以及网络环境<br><img src="https://tc.ets2la.cn/d/img/25-12/20251202131000.png" alt="" loading="lazy"><br> 安装完成后<strong>取消</strong>勾选<code>启动ETS2LA</code>，然后点击完成<br><img src="https://tc.ets2la.cn/d/img/25-12/20251202131048.png" alt="" loading="lazy"></p><div class="tip custom-block"><p class="custom-block-title">提示</p><p>这里建议取消勾选<code>启动ETS2LA</code>，因为在启动ETS2LA时会下载一些文件，如果你的网络不好，可能会卡在下载文件上，导致每次启动都会出现警告；在后面的教程中 会教如何解决</p></div>',3))])}const x=n(g,[["render",m]]);export{T as __pageData,x as default};
